"""Step 4B: evaluate uncertainty generated by Steps 1-3."""

from __future__ import annotations

import os
import subprocess
import sys
from pathlib import Path

from env_utils import load_quickstart_env


QUICK_START = Path(__file__).resolve().parents[1]
REPO_ROOT = QUICK_START.parent


def main() -> None:
    load_quickstart_env()
    env = os.environ.copy()
    env["PYTHONPATH"] = str(REPO_ROOT) + os.pathsep + env.get("PYTHONPATH", "")

    uncertainty_path = QUICK_START / "generated" / "results" / "uncertainty_generated.pkl"
    if not uncertainty_path.exists():
        subprocess.run(
            [
                sys.executable,
                "-m",
                "matu.fit_to_uncertainty",
                "--fit_dict",
                str(QUICK_START / "generated" / "results" / "fit_dict_generated.pkl"),
                "--out",
                str(uncertainty_path),
            ],
            check=True,
            cwd=str(REPO_ROOT),
            env=env,
        )

    cmd = [
        sys.executable,
        "-m",
        "matu.evaluate_uncertainty",
        "--uncertainty",
        str(uncertainty_path),
        "--labels",
        str(QUICK_START / "results" / "accuracy_dict_Math_qwen2.5.pkl"),
        "--score_mode",
        "raw",
    ]
    subprocess.run(cmd, check=True, cwd=str(REPO_ROOT), env=env)


if __name__ == "__main__":
    main()
